SELECT export_id AS exportId, export_type AS exportType, export_format AS exportFormat, project_count AS projectCount, export_status AS exportStatus, export_user_id AS exportUserId, export_user_name AS exportUserName, file_name AS fileName, error_msg AS errorMsg, export_date AS exportDate FROM project_ledger_export WHERE is_del = 0
